const body = $('Recibir simulación').first().json.body || {};
const cfg = $input.all().map(i => i.json);
const tokenCfg = (cfg.find(x => x && x.clave === 'simulador_token') || {}).valor || null;
const auth_ok = !!tokenCfg && String(body.token || '') === String(tokenCfg);
const b64 = String(body.imagen_b64 || '').replace(/^data:[^;]+;base64,/, '');
const valido = b64.length > 100;
if (!auth_ok || !valido) return [{ json: { auth_ok, valido } }];
const fileName = body.filename || 'foto.jpg';
const carpeta = String(body.carpeta || 'sin-carpeta');
const operario = String(body.operario || 'operario-sim');
const chatId = String(body.chat_id || '-1003908341093');
const messageId = 'sim' + Date.now() + Math.floor(Math.random() * 1000);
const proceso = 'calidad-lata';
const evidenceId = proceso + ':' + chatId + ':' + messageId;
const imagenRef = proceso + '/' + chatId + '/' + messageId + '.jpg';
return [{ json: { auth_ok, valido, evidence_id: evidenceId, proceso, linea_fallback: carpeta, equipo: '', capturado_en: new Date().toISOString(), imagen_ref: imagenRef, origen: { chat_id: chatId, chat_title: carpeta, from_id: operario, message_id: messageId, via: 'simulador' }, caption: '', has_photo: true }, binary: { data: { data: b64, mimeType: 'image/jpeg', fileName } } }];

const n = $('Validar y preparar').first().json;
const hash = $('Hash imagen').first().json.imagen_hash || null;
const lineaRows = $('Buscar línea').all().map(i => i.json).filter(j => j && j.linea);
const linea = lineaRows.length ? lineaRows[0].linea : n.linea_fallback;
const equipo = lineaRows.length ? (lineaRows[0].equipo || '') : '';
const proceso = lineaRows.length ? (lineaRows[0].proceso || n.proceso) : n.proceso;
const dupRows = $input.all().map(i => i.json).filter(j => j && j.dup_evidence_id);
const estado = dupRows.length ? 'duplicada' : 'recibido';
const duplicada_de = dupRows.length ? dupRows[0].dup_evidence_id : null;
return [{ json: { ...n, linea, equipo, proceso, imagen_hash: hash, estado, duplicada_de } }];
